postprocess_accum_11_loop:
    li t1, 11
    bge t0, t1, postprocess_accum_11_done
    slli t2, t0, 2
    add t3, a0, t2
    lw t4, 0(t3)
    blt t4, zero, postprocess_accum_11_zero
    andi t4, t4, 255
    j postprocess_accum_11_store
postprocess_accum_11_zero:
    li t4, 0
postprocess_accum_11_store:
    add t5, a1, t0
    sb t4, 0(t5)
    addi t0, t0, 1
    j postprocess_accum_11_loop
postprocess_accum_11_done:
